import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;

// Fake AI service for deterministic tests (no real API calls):
@Service
public class FakeAiService {
    // keyword → scripted response mapping:
    private final Map<String, String> responses = new LinkedHashMap<>() {{
        put("cibil", "Home loan requires minimum CIBIL score of 700.");
        put("balance", "Your account balance is ₹50,000.");
        put("emi", "Your monthly EMI is ₹15,000.");
        put("refund", "Refund will be credited in 5-7 business days.");
        put("webhook", "Webhooks are retried up to 5 times over 24 hours.");
    }};

    public String answer(String question) {
        String lower = question.toLowerCase();
        return responses.entrySet().stream()
            .filter(e -> lower.contains(e.getKey()))
            .map(Map.Entry::getValue)
            .findFirst()
            .orElse("I don't have information about that topic.");
    }

    public boolean knowsAbout(String keyword) {
        return responses.containsKey(keyword.toLowerCase());
    }

    // Add scripted response for test setup:
    public void addResponse(String keyword, String response) {
        responses.put(keyword.toLowerCase(), response);
    }
}

@SpringBootTest
class FakeAiServiceTest {
    @Autowired FakeAiService fakeAi;

    @Test void knownQuestion_returnsScriptedResponse() {
        String result = fakeAi.answer("What CIBIL score for home loan?");
        assertEquals("Home loan requires minimum CIBIL score of 700.", result);
    }
    @Test void unknownQuestion_returnsDefault() {
        String result = fakeAi.answer("Best pizza recipe");
        assertEquals("I don't have information about that topic.", result);
    }
    @Test void customResponse_canBeAdded() {
        fakeAi.addResponse("insurance", "HDFC Life Insurance: term plans from ₹500/month.");
        assertTrue(fakeAi.answer("Tell me about insurance").contains("HDFC Life"));
    }
}

import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;

@Service
public class AiResponseAssertions {

    // Factual assertion: AI must mention this key fact
    public void containsFact(String response, String expectedFact) {
        assertTrue(
            response.toLowerCase().contains(expectedFact.toLowerCase()),
            "AI response should contain fact '" + expectedFact + "' but was: " + response
        );
    }

    // Numeric fact: response must contain this number
    public void containsNumber(String response, String number) {
        assertTrue(
            response.contains(number),
            "AI response should contain '" + number + "' but was: " + response
        );
    }

    // Anti-hallucination: must NOT contain these banned/fabricated terms
    public void doesNotHallucinate(String response, List<String> bannedTerms) {
        for (String term : bannedTerms) {
            assertFalse(
                response.toLowerCase().contains(term.toLowerCase()),
                "AI hallucinated banned term '" + term + "' in response: " + response
            );
        }
    }

    // Combined: response is factually correct
    public void assertFactuallyCorrect(String response, List<String> requiredFacts, List<String> bannedTerms) {
        requiredFacts.forEach(fact -> containsFact(response, fact));
        doesNotHallucinate(response, bannedTerms);
    }
}

@SpringBootTest
class AiResponseAssertionsTest {
    @Autowired AiResponseAssertions assertions;

    private final String HDFC_CIBIL_RESPONSE =
        "HDFC Bank home loan requires a minimum CIBIL score of 700. The maximum loan amount is ₹5 crore.";

    @Test void factPresent_passes() {
        assertions.containsFact(HDFC_CIBIL_RESPONSE, "700");
        assertions.containsFact(HDFC_CIBIL_RESPONSE, "CIBIL");
        assertions.containsFact(HDFC_CIBIL_RESPONSE, "home loan");
    }
    @Test void numberPresent_passes() {
        assertions.containsNumber(HDFC_CIBIL_RESPONSE, "700");
        assertions.containsNumber(HDFC_CIBIL_RESPONSE, "5 crore");
    }
    @Test void hallucination_absent() {
        // These terms would indicate hallucination (not in actual HDFC policy):
        assertions.doesNotHallucinate(HDFC_CIBIL_RESPONSE,
            List.of("zero interest", "guaranteed approval", "no documents needed"));
    }
}

