    static WireMockExtension wireMock;

    // Point Spring AI to WireMock instead of real Anthropic API:
    @DynamicPropertySource
    static void configureWireMock(DynamicPropertyRegistry registry) {
        registry.add("spring.ai.anthropic.base-url", () -> "http://localhost:9999");
        registry.add("spring.ai.anthropic.api-key", () -> "test-key-wiremock");
    }

