@Service
public class HdfcAiServiceWithFallback {
    private final ChatClient chatClient;

    // Cached fallback responses for common questions:
    private static final Map<String, String> FALLBACK = Map.of(
        "balance", "Please check your HDFC Mobile Banking app for current balance.",
        "loan", "Contact HDFC customer care at 1800-XXX for loan queries.",
        "default", "AI service temporarily unavailable. Please call 1800-XXX-XXXX."
    );

    public HdfcAiServiceWithFallback(ChatClient.Builder builder) {
        this.chatClient = builder.defaultSystem("HDFC Bank AI.").build();
    }

    public String answer(String question) {
        try {
            return chatClient.prompt().user(question).call().content();
        } catch (Exception e) {
            // Graceful degradation: return relevant cached response
            String lower = question.toLowerCase();
            if (lower.contains("balance")) return FALLBACK.get("balance");
            if (lower.contains("loan")) return FALLBACK.get("loan");
            return FALLBACK.get("default");
        }
    }
}

