record EvaluationResult(int score, String feedback, boolean isAcceptable) {
    // Score 1-5: 1=terrible, 3=acceptable, 5=excellent
    static EvaluationResult parse(String aiEvalResponse) {
        // Parse simple format: "SCORE: 4\nFEEDBACK: Response is factual and relevant."
        int score = 3; // default
        String feedback = aiEvalResponse;
        try {
            if (aiEvalResponse.contains("SCORE:")) {
                String scorePart = aiEvalResponse.split("SCORE:")[1].trim().split("\n")[0];
                score = Integer.parseInt(scorePart.trim());
            }
            if (aiEvalResponse.contains("FEEDBACK:")) {
                feedback = aiEvalResponse.split("FEEDBACK:")[1].trim();
            }
        } catch (Exception ignored) {}
        return new EvaluationResult(score, feedback, score >= 3);
    }
}

@Service
class AiEvaluator {
    // Simulated LLM-as-judge (in production: second AI call)
    public EvaluationResult evaluate(String question, String answer, String referenceDoc) {
        // Criteria checks (simplified):
        boolean containsRelevantFact = answer.toLowerCase().contains(question.split(" ")[0].toLowerCase());
        boolean isReasonableLength = answer.length() > 10 && answer.length() < 2000;
        boolean noObviousHallucination = !answer.toLowerCase().contains("guaranteed") &&
                                         !answer.toLowerCase().contains("zero cost");

        int score = 0;
        List<String> issues = new ArrayList<>();
        if (containsRelevantFact) score += 2; else issues.add("Missing relevant fact");
        if (isReasonableLength) score += 2; else issues.add("Inappropriate length");
        if (noObviousHallucination) score += 1; else issues.add("Potential hallucination");

        String feedback = issues.isEmpty()
            ? "Response is accurate and well-structured."
            : "Issues: " + String.join(", ", issues);

        return new EvaluationResult(score, feedback, score >= 3);
    }
}

@SpringBootTest
class LlmJudgeTest {
    @Autowired AiEvaluator evaluator;

    @Test void goodResponse_highScore() {
        EvaluationResult result = evaluator.evaluate(
            "What is CIBIL requirement",
            "HDFC home loan requires minimum CIBIL score of 700. Income proof is mandatory.",
            "HDFC requires CIBIL 700+"
        );
        assertTrue(result.isAcceptable());
        assertTrue(result.score() >= 3);
    }
    @Test void hallucinatedResponse_lowScore() {
        EvaluationResult result = evaluator.evaluate(
            "loan requirements",
            "HDFC offers guaranteed approval with zero cost processing!",
            "HDFC requires CIBIL 700"
        );
        assertFalse(result.isAcceptable()); // hallucination detected
    }
    @Test void parseScore_fromAiJudgeResponse() {
        String judgeResponse = "SCORE: 4\nFEEDBACK: Response is factual and relevant.";
        EvaluationResult r = EvaluationResult.parse(judgeResponse);
        assertEquals(4, r.score());
        assertTrue(r.isAcceptable());
    }
}

