import org.springframework.ai.vectorstore.*;
import org.springframework.ai.document.Document;
import org.springframework.ai.embedding.EmbeddingModel;
import org.springframework.ai.chat.client.ChatClient;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.boot.test.mock.mockito.MockBean;
import org.springframework.beans.factory.annotation.Autowired;
import static org.mockito.Mockito.*;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;
import java.util.stream.Collectors;

@Service
class TestableRagPipeline {
    private final VectorStore vectorStore;
    private final ChatClient chatClient;

    TestableRagPipeline(VectorStore vs, ChatClient.Builder b) {
        vectorStore = vs;
        chatClient = b.defaultSystem("Answer ONLY from context. If not in context: 'Not available.'").build();
    }

    // Stage 1: Ingest
    public int ingest(List<Document> docs) {
        vectorStore.add(docs);
        return docs.size();
    }

    // Stage 2: Retrieve
    public List<Document> retrieve(String question) {
        return vectorStore.similaritySearch(SearchRequest.query(question).withTopK(2));
    }

    // Stage 3: Generate
    public String generate(String question, List<Document> context) {
        String ctx = context.stream().map(Document::getContent).collect(Collectors.joining("\n"));
        return chatClient.prompt()
            .user(u -> u.text("Context:\n{ctx}\nQuestion: {q}").param("ctx", ctx).param("q", question))
            .call().content();
    }

    // Full pipeline:
    public String answer(String question) {
        List<Document> context = retrieve(question);
        if (context.isEmpty()) return "Not available.";
        return generate(question, context);
    }
}

@SpringBootTest
class RagPipelineTest {
    @Autowired EmbeddingModel embeddingModel;
    @MockBean ChatClient.Builder chatBuilder;

    TestableRagPipeline buildPipeline() {
        InMemoryVectorStore store = new InMemoryVectorStore(embeddingModel);
        // Mock the ChatClient chain:
