        when(chatBuilder.defaultSystem(any())).thenReturn(chatBuilder);
        when(chatBuilder.build()).thenReturn(client);
        when(client.prompt()).thenReturn(spec);
        when(spec.user(any(java.util.function.Consumer.class))).thenReturn(spec);
        when(spec.call()).thenReturn(call);
        when(call.content()).thenReturn("Webhooks retry 5 times.");
        return new TestableRagPipeline(store, chatBuilder);
    }

    @Test void ingestion_returnsCount() {
        var pipeline = buildPipeline();
        int count = pipeline.ingest(List.of(
            new Document("Webhook retries: 5 times.", Map.of("src","webhooks.md")),
            new Document("Refund time: 5-7 days.", Map.of("src","refunds.md"))
        ));
