    }
    @Test void retrieval_findsSimilarDocs() {
        var pipeline = buildPipeline();
        pipeline.ingest(List.of(new Document("Webhook retries 5 times.", Map.of("src","webhooks.md"))));
        List<Document> results = pipeline.retrieve("webhook retry policy");
