import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;

record EvalCase(String question, List<String> expectedFacts, List<String> bannedTerms) {}
record EvalResult(int total, int passed, double accuracy, List<String> failures) {}

@Service
class HdfcEvalDataset {
    public List<EvalCase> getCases() {
        return List.of(
            new EvalCase(
                "What CIBIL score is needed for an HDFC home loan?",
                List.of("700", "CIBIL", "home loan"),
                List.of("guaranteed", "no CIBIL", "any score")
            ),
            new EvalCase(
                "How long does HDFC refund take?",
                List.of("5", "7", "days", "business"),
                List.of("instant", "same day", "24 hours")
            ),
            new EvalCase(
                "What is the HDFC personal loan interest rate?",
                List.of("%", "interest", "rate"),
                List.of("0%", "free", "zero interest")
            ),
            new EvalCase(
                "How much can I borrow for HDFC car loan?",
                List.of("lakh", "loan"),
                List.of("unlimited", "any amount")
            ),
            new EvalCase(
                "What documents are needed for HDFC home loan?",
                List.of("income", "document", "proof"),
                List.of("no documents", "instant approval")
            )
        );
    }
}

@Service
class EvalRunner {
    public EvalResult run(List<EvalCase> cases, java.util.function.Function<String,String> aiService) {
        List<String> failures = new ArrayList<>();
        int passed = 0;
        for (EvalCase ec : cases) {
            String response = aiService.apply(ec.question());
            boolean factsOk = ec.expectedFacts().stream().allMatch(f -> response.toLowerCase().contains(f.toLowerCase()));
            boolean noHallucination = ec.bannedTerms().stream().noneMatch(b -> response.toLowerCase().contains(b.toLowerCase()));
            if (factsOk && noHallucination) {
                passed++;
            } else {
                failures.add(ec.question() + " → " + (factsOk ? "hallucination" : "missing fact"));
            }
        }
        return new EvalResult(cases.size(), passed, (double)passed/cases.size()*100, failures);
    }
}

@SpringBootTest
class EvalDatasetTest {
    @Autowired HdfcEvalDataset dataset;
    @Autowired EvalRunner runner;
    @Autowired FakeAiService fakeAi;

    @Test void dataset_has5Cases() {
        assertEquals(5, dataset.getCases().size());
    }
    @Test void evalRunner_measuresAccuracy() {
        // Setup fake AI with relevant responses:
        fakeAi.addResponse("cibil", "HDFC home loan requires minimum CIBIL score of 700.");
        fakeAi.addResponse("refund", "HDFC refund takes 5-7 business days to process.");
        fakeAi.addResponse("interest", "HDFC personal loan rate: 10.5% to 15.0% per annum.");
        fakeAi.addResponse("car", "HDFC car loan: up to ₹50 lakh, 1-7 years.");
        fakeAi.addResponse("documents", "Required: income proof, ID proof, address proof.");

        EvalResult result = runner.run(dataset.getCases(), fakeAi::answer);
        assertTrue(result.accuracy() > 0, "At least some cases should pass");
    }
    @Test void hallucination_detected() {
        fakeAi.addResponse("loan", "HDFC offers guaranteed approval with zero interest!");
        List<EvalCase> cases = List.of(new EvalCase(
            "Tell me about HDFC loan",
            List.of("HDFC"),
            List.of("guaranteed", "zero interest")
        ));
        EvalResult result = runner.run(cases, fakeAi::answer);
        assertEquals(0, result.passed()); // hallucination caught
    }
}

import org.springframework.stereotype.*;
