record AiSupportResponse(String answer, List<String> citations, String sessionId) {
    boolean isValid() {
        return answer != null && !answer.isBlank()
            && citations != null
            && sessionId != null && !sessionId.isBlank();
    }
}

@Service
class AiResponseSchemaValidator {
    // Validates the response matches the consumer's expected schema:
    public record ValidationResult(boolean valid, List<String> errors) {}

    public ValidationResult validate(AiSupportResponse response) {
        List<String> errors = new ArrayList<>();
        if (response == null) { errors.add("Response is null"); return new ValidationResult(false, errors); }
        if (response.answer() == null || response.answer().isBlank()) errors.add("answer is required and non-empty");
        if (response.citations() == null) errors.add("citations must be a list (can be empty)");
        if (response.sessionId() == null || response.sessionId().isBlank()) errors.add("sessionId is required");
        // Answer length contract: between 10 and 2000 characters:
        if (response.answer() != null && response.answer().length() > 2000)
            errors.add("answer exceeds max length 2000");
        return new ValidationResult(errors.isEmpty(), errors);
    }
}

@Service
class AiContractTestHelper {
    public AiSupportResponse buildValidResponse(String sessionId, String answer, String... sources) {
        return new AiSupportResponse(answer, List.of(sources), sessionId);
    }
    public AiSupportResponse buildInvalidResponse() {
        return new AiSupportResponse(null, null, ""); // violates contract
    }
}

@SpringBootTest
class AiContractTest {
    @Autowired AiResponseSchemaValidator validator;
    @Autowired AiContractTestHelper helper;

    @Test void validResponse_passesContract() {
        var response = helper.buildValidResponse(
            "session-123",
            "HDFC home loan requires CIBIL score of 700.",
            "home-loan.pdf"
        );
        ValidationResult result = validator.validate(response);
        assertTrue(result.valid(), "Should pass: " + result.errors());
        assertTrue(result.errors().isEmpty());
    }
    @Test void nullAnswer_failsContract() {
        var response = helper.buildInvalidResponse();
        ValidationResult result = validator.validate(response);
        assertFalse(result.valid());
        assertTrue(result.errors().stream().anyMatch(e -> e.contains("answer")));
    }
    @Test void emptyCitations_isValid() {
        // Empty citations list is valid (some answers have no specific source)
        var response = new AiSupportResponse(
            "Your query has been noted.", List.of(), "session-456"
        );
        ValidationResult result = validator.validate(response);
        assertTrue(result.valid()); // empty citations is OK
    }
}

import org.springframework.stereotype.*;
