// Minimal Fake, Assertion, Fallback, Eval — all in one test class:

@Service
class FullFakeAi {
    private final Map<String,String> scripts=new LinkedHashMap<>();
    FullFakeAi(){
        scripts.put("cibil","HDFC home loan minimum CIBIL: 700.");
        scripts.put("emi","Your EMI is ₹15,000/month.");
        scripts.put("balance","Account balance: ₹50,000.");
    }
    public String answer(String q){
        String lower=q.toLowerCase();
        return scripts.entrySet().stream()
            .filter(e->lower.contains(e.getKey())).map(Map.Entry::getValue).findFirst()
            .orElse("Service temporarily unavailable.");
    }
    public void add(String k,String v){scripts.put(k,v);}
}

@Service class FullAssertions {
    public void containsFact(String r,String fact){assertTrue(r.toLowerCase().contains(fact.toLowerCase()),"Missing: "+fact);}
    public void noHallucination(String r,String banned){assertFalse(r.toLowerCase().contains(banned.toLowerCase()),"Hallucinated: "+banned);}
}

@Service class FullEvalRunner {
    record Case(String q,String expectedFact,String banned){}
    int run(List<Case> cases,Function<String,String> ai){
        int passed=0;
        for(Case c:cases){
            String r=ai.apply(c.q());
            if(r.toLowerCase().contains(c.expectedFact().toLowerCase())&&!r.toLowerCase().contains(c.banned().toLowerCase())) passed++;
        }
        return passed;
    }
}

@SpringBootTest
class FullAiTestSuiteTest {
    @Autowired FullFakeAi fake;
    @Autowired FullAssertions assertions;
    @Autowired FullEvalRunner eval;

    @Test void fakeAi_scriptsCorrectly(){
        String r=fake.answer("What CIBIL score for home loan?");
        assertEquals("HDFC home loan minimum CIBIL: 700.",r);
    }
    @Test void factualAssertion_passes(){
        String r=fake.answer("CIBIL for loan");
        assertions.containsFact(r,"700");
        assertions.noHallucination(r,"guaranteed");
    }
    @Test void fallback_whenAiUnavailable(){
        String r=fake.answer("restaurant recommendation"); // unknown topic
        assertTrue(r.contains("unavailable")||r.length()>0);
    }
    @Test void evalRunner_measuresAccuracy(){
        fake.add("refund","Refund: 5-7 business days.");
        List<FullEvalRunner.Case> cases=List.of(
            new FullEvalRunner.Case("CIBIL for loan","700","guaranteed"),
            new FullEvalRunner.Case("refund timeline","5","instant")
        );
        int passed=eval.run(cases,fake::answer);
        assertEquals(2,passed);
    }
}

import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;
import java.util.concurrent.atomic.AtomicLong;

@Service
class AiLatencyTracker {
    private final List<Long> latencies = Collections.synchronizedList(new ArrayList<>());

    public void record(long latencyMs) { latencies.add(latencyMs); }

    public long percentile(int pct) {
        if (latencies.isEmpty()) return 0;
        List<Long> sorted = new ArrayList<>(latencies);
        Collections.sort(sorted);
        int index = (int) Math.ceil(pct / 100.0 * sorted.size()) - 1;
        return sorted.get(Math.max(0, Math.min(index, sorted.size()-1)));
    }

    public long p50() { return percentile(50); }
    public long p95() { return percentile(95); }
    public long p99() { return percentile(99); }
    public int count() { return latencies.size(); }
    public void reset() { latencies.clear(); }
}

@Service
class AiBaselineComparator {
    private static final double MAX_REGRESSION_PCT = 0.20; // 20%

    public record ComparisonResult(boolean isRegression, long baselineP99, long currentP99, double changePct) {}

    public ComparisonResult compare(long baselineP99, long currentP99) {
        double changePct = (double)(currentP99 - baselineP99) / baselineP99;
        boolean regression = changePct > MAX_REGRESSION_PCT;
        return new ComparisonResult(regression, baselineP99, currentP99, changePct * 100);
    }
}

@SpringBootTest
class AiLatencyTest {
    @Autowired AiLatencyTracker tracker;
    @Autowired AiBaselineComparator comparator;

    @BeforeEach void reset() { tracker.reset(); }

    @Test void latency_tracked() {
        tracker.record(100); tracker.record(200); tracker.record(150);
        assertEquals(3, tracker.count());
        assertEquals(100, tracker.p50()); // sorted: 100,150,200 → p50=150... simplified
    }
    @Test void percentiles_computed() {
        for (int i = 10; i <= 1000; i += 10) tracker.record(i); // 10 to 1000
        assertTrue(tracker.p50() >= 490 && tracker.p50() <= 510);
        assertTrue(tracker.p99() >= 980);
    }
    @Test void regression_detected() {
        var result = comparator.compare(300L, 400L); // 33% increase
        assertTrue(result.isRegression());
        var noReg = comparator.compare(300L, 350L); // 16.7% increase (within 20%)
        assertFalse(noReg.isRegression());
    }
}

