@Service class T5FakeAi {
    private final Map<String,String> scripts=new LinkedHashMap<>();
    T5FakeAi(){
        scripts.put("cibil","HDFC requires CIBIL 700 for home loan.");
        scripts.put("balance","Balance: ₹50,000 available.");
        scripts.put("refund","Refund in 5-7 business days.");
        scripts.put("interest","Home loan rate: 8.5% per annum.");
        scripts.put("emi","Monthly EMI: ₹15,000.");
    }
    public String answer(String q){
        String l=q.toLowerCase();
        return scripts.entrySet().stream().filter(e->l.contains(e.getKey())).map(Map.Entry::getValue).findFirst().orElse("UNAVAILABLE");
    }
}

@Service class T5Validator {
    record VResult(boolean ok,List<String> errors){}
    public VResult validate(String response,List<String> facts,List<String> banned,int maxLen){
        List<String> errors=new ArrayList<>();
        if(response==null||response.isBlank()) {errors.add("empty response");return new VResult(false,errors);}
        if(response.length()>maxLen) errors.add("too long: "+response.length());
        facts.stream().filter(f->!response.toLowerCase().contains(f.toLowerCase())).forEach(f->errors.add("missing: "+f));
        banned.stream().filter(b->response.toLowerCase().contains(b.toLowerCase())).forEach(b->errors.add("banned: "+b));
        return new VResult(errors.isEmpty(),errors);
    }
}

@Service class T5EvalRunner {
    record Case(String q,String fact,String banned){}
    record Result(int passed,int total){double accuracy(){return (double)passed/total*100;}}
    public Result run(List<Case> cases,Function<String,String> ai){
        int p=0;
        for(Case c:cases){
            String r=ai.apply(c.q());
            if(r.toLowerCase().contains(c.fact().toLowerCase())&&!r.toLowerCase().contains(c.banned().toLowerCase())) p++;
        }
        return new Result(p,cases.size());
    }
}

@Service class T5FallbackSvc {
    private final Map<String,String> cache=Map.of("balance","Balance unavailable, please use mobile app.","loan","Call 1800-XXX for loan queries.");
    public String ask(String topic,Function<String,String> ai){
        try{String r=ai.apply(topic);if("UNAVAILABLE".equals(r)) throw new RuntimeException();return r;}
        catch(Exception e){return cache.getOrDefault(topic,"Service unavailable.");}
    }
}

@SpringBootTest
class M26T5SynthesisTest {
    @Autowired T5FakeAi fake;
    @Autowired T5Validator validator;
    @Autowired T5EvalRunner eval;
    @Autowired T5FallbackSvc fallback;

    @Test void fakeAi_correctResponse(){assertEquals("HDFC requires CIBIL 700 for home loan.",fake.answer("cibil score?"));}
    @Test void validator_passesGoodResponse(){
        T5Validator.VResult r=validator.validate("Balance: ₹50,000",List.of("50,000"),List.of("guaranteed"),500);
        assertTrue(r.ok());
    }
    @Test void eval_measuresAccuracy(){
        List<T5EvalRunner.Case> cases=List.of(
            new T5EvalRunner.Case("cibil home loan","700","guaranteed"),
            new T5EvalRunner.Case("refund time","5","instant")
        );
        T5EvalRunner.Result result=eval.run(cases,fake::answer);
        assertEquals(2,result.passed());
    }
    @Test void fallback_whenUnavailable(){
        String r=fallback.ask("balance",q->"UNAVAILABLE"); // AI always returns UNAVAILABLE
        assertTrue(r.contains("mobile app")||r.contains("unavailable")||(r.length()>0));
    }
